    /**
     * Safely update dependencies while maintaining lock file integrity.
     * Supports updating specific packages or all packages.
     */
    updateDependencies(packages = [], options = {}) {
        const {
            dryRun = false,
            major = false,
            saveExact = false
        } = options;

        console.log('📦 Updating dependencies...\n');

        // Always backup before updates
        this.backupLockFile();

        if (packages.length === 0) {
            // Update all packages
            let command = 'npm update';
            if (dryRun) command += ' --dry-run';
            if (saveExact) command += ' --save-exact';

            console.log(`   Running: ${command}`);
            try {
                execSync(command, { cwd: this.projectRoot, stdio: 'inherit' });
            } catch (error) {
                console.error('❌ Update failed:', error.message);
                throw error;
            }
        } else {
            // Update specific packages
            for (const pkg of packages) {
                let command = `npm update ${pkg}`;
                if (dryRun) command += ' --dry-run';
                if (saveExact) command += ' --save-exact';

                console.log(`   Updating: ${pkg}`);
                try {
                    execSync(command, { cwd: this.projectRoot, stdio: 'inherit' });
                } catch (error) {
                    console.error(`   ❌ Failed to update ${pkg}:`, error.message);
                }
            }
        }

        if (!dryRun) {
            console.log('\n   Showing changes:');
            this.diffLockFiles();
        }
    }

    /**
     * Fix lock file by regenerating it from package.json
     */
    fixLockFile() {
        console.log('🔧 Fixing package-lock.json...\n');

        this.backupLockFile();

        // Remove node_modules and lock file, then reinstall
        const nodeModulesPath = path.join(this.projectRoot, 'node_modules');

        if (fs.existsSync(this.packageLockPath)) {
            fs.unlinkSync(this.packageLockPath);
            console.log('   Removed existing package-lock.json');
        }

        if (fs.existsSync(nodeModulesPath)) {
            console.log('   Removing node_modules (this may take a moment)...');
            fs.rmSync(nodeModulesPath, { recursive: true, force: true });
            console.log('   Removed node_modules');
        }

        console.log('   Reinstalling dependencies...');
        try {
            execSync('npm install', { cwd: this.projectRoot, stdio: 'inherit' });
            console.log('\n✅ package-lock.json regenerated successfully.');
            this.printLockFileStats();
        } catch (error) {
            console.error('\n❌ Fix failed:', error.message);
            console.log('   Attempting to restore backup...');
            this.restoreLatestBackup();
            throw error;
        }
    }

    // =========================================================================
    // SECTION 4: Backup & Restore
    // =========================================================================

    /**
     * Create a timestamped backup of the current lock file
     */
    backupLockFile() {
        if (!fs.existsSync(this.packageLockPath)) {
            console.log('   No package-lock.json to backup.');
            return null;
        }

        if (!fs.existsSync(this.lockBackupDir)) {
            fs.mkdirSync(this.lockBackupDir, { recursive: true });

            // Add .lock-backups to .gitignore if not already there
            const gitignorePath = path.join(this.projectRoot, '.gitignore');
            if (fs.existsSync(gitignorePath)) {
                const gitignore = fs.readFileSync(gitignorePath, 'utf8');
                if (!gitignore.includes('.lock-backups')) {
                    fs.appendFileSync(gitignorePath, '\n.lock-backups/\n');
                }
            }
        }

        const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
        const backupName = `package-lock.${timestamp}.json`;
        const backupPath = path.join(this.lockBackupDir, backupName);

        fs.copyFileSync(this.packageLockPath, backupPath);
        console.log(`   📋 Backup created: .lock-backups/${backupName}`);

        // Keep only last 10 backups
        this._pruneBackups(10);

        return backupPath;
    }

    /**
     * Restore the most recent backup
     */
    restoreLatestBackup() {
        if (!fs.existsSync(this.lockBackupDir)) {
            console.log('   No backups available.');
            return false;
        }

        const backups = fs.readdirSync(this.lockBackupDir)
            .filter(f => f.startsWith('package-lock.') && f.endsWith('.json'))
            .sort()
            .reverse();

        if (backups.length === 0) {
            console.log('   No backups available.');
            return false;
        }

        const latestBackup = path.join(this.lockBackupDir, backups[0]);
        fs.copyFileSync(latestBackup, this.packageLockPath);
        console.log(`   📋 Restored from backup: ${backups[0]}`);
        return true;
    }

    /**
     * List all available backups
     */
    listBackups() {
        if (!fs.existsSync(this.lockBackupDir)) {
            console.log('   No backups directory found.');
            return [];
        }

        const backups = fs.readdirSync(this.lockBackupDir)
            .filter(f => f.startsWith('package-lock.') && f.endsWith('.json'))
            .sort()
            .reverse();

        console.log(`\n📋 Available backups (${backups.length}):\n`);
        backups.forEach((backup, index) => {
            const filePath = path.join(this.lockBackupDir, backup);
            const stats = fs.statSync(filePath);
            const sizeKB = (stats.size / 1024).toFixed(1);
            console.log(`   ${index + 1}. ${backup} (${sizeKB} KB)`);
        });

        return backups;
    }

    _pruneBackups(maxBackups) {
        const backups = fs.readdirSync(this.lockBackupDir)
            .filter(f => f.startsWith('package-lock.') && f.endsWith('.json'))
            .sort();

        while (backups.length > maxBackups) {
            const oldest = backups.shift();
            fs.unlinkSync(path.join(this.lockBackupDir, oldest));
        }
    }

