    /**
     * Run security audit and generate a report
     */
    auditDependencies(options = {}) {
        const { fix = false, production = false } = options;

        console.log('🔒 Running security audit...\n');

        let command = 'npm audit --json';
        if (production) command += ' --production';

        try {
            const output = execSync(command, {
                cwd: this.projectRoot,
                stdio: 'pipe',
                encoding: 'utf8'
            });

            const auditResult = JSON.parse(output);
            this._printAuditSummary(auditResult);

            // Save full report
            fs.writeFileSync(this.reportPath, JSON.stringify(auditResult, null, 2));
            console.log(`\n   Full report saved to: lock-audit-report.json`);

            if (fix && auditResult.metadata?.vulnerabilities) {
                const totalVulns = Object.values(auditResult.metadata.vulnerabilities)
                    .reduce((sum, count) => sum + count, 0);

                if (totalVulns > 0) {
                    console.log('\n   Attempting automatic fix...');
                    this.backupLockFile();
                    execSync('npm audit fix', { cwd: this.projectRoot, stdio: 'inherit' });
                }
            }

            return auditResult;
        } catch (error) {
            // npm audit exits with non-zero when vulnerabilities are found
            if (error.stdout) {
                try {
                    const auditResult = JSON.parse(error.stdout);
                    this._printAuditSummary(auditResult);
                    fs.writeFileSync(this.reportPath, JSON.stringify(auditResult, null, 2));
                    console.log(`\n   Full report saved to: lock-audit-report.json`);

                    if (fix) {
                        console.log('\n   Attempting automatic fix...');
                        this.backupLockFile();
                        try {
                            execSync('npm audit fix', { cwd: this.projectRoot, stdio: 'inherit' });
                        } catch (fixError) {
                            console.log('   Some vulnerabilities require manual review.');
                            console.log('   Run `npm audit fix --force` for breaking changes (use with caution).');
                        }
                    }

                    return auditResult;
                } catch (parseError) {
                    // Fall through
                }
            }
            console.error('   ❌ Audit failed:', error.message);
            return null;
        }
    }

    _printAuditSummary(auditResult) {
        const meta = auditResult.metadata;
        if (!meta) {
            console.log('   No metadata in audit result.');
            return;
        }

        const vulns = meta.vulnerabilities || {};
        console.log('   Vulnerability Summary:');
        console.log(`   ├── Critical: ${vulns.critical || 0}`);
        console.log(`   ├── High:     ${vulns.high || 0}`);
        console.log(`   ├── Moderate: ${vulns.moderate || 0}`);
        console.log(`   ├── Low:      ${vulns.low || 0}`);
        console.log(`   └── Info:     ${vulns.info || 0}`);

        const total = Object.values(vulns).reduce((sum, count) => sum + count, 0);
        console.log(`\n   Total: ${total} vulnerabilities in ${meta.totalDependencies || '?'} packages`);
    }

